.darma-loader-uiverse-liquid-aurora-progress__liquid-loader {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 5px;
  padding: 20px;
  font-family: system-ui, sans-serif;
}

.darma-loader-uiverse-liquid-aurora-progress__track {
position: relative;
width: 180px;
height: 32px;
background: linear-gradient(135deg, #2a2a2a, #1a1a1a);
border-radius: 16px;
overflow: hidden;
box-shadow:
inset 0 2px 4px rgba(0, 0, 0, 0.6),
0 1px 3px rgba(255, 255, 255, 0.1);
}

.darma-loader-uiverse-liquid-aurora-progress__liquid-fill {
position: absolute;
top: 2px;
left: 2px;
height: calc(100% - 4px);
background: linear-gradient(90deg, #4f46e5, #7c3aed, #ec4899, #f59e0b);
border-radius: 14px;
animation:
darma-loader-uiverse-liquid-aurora-progress-fillProgress 4s ease-out infinite,
darma-loader-uiverse-liquid-aurora-progress-colorShift 3s linear infinite;
box-shadow:
0 0 12px rgba(124, 58, 237, 0.4),
inset 0 1px 2px rgba(255, 255, 255, 0.2);
}

.darma-loader-uiverse-liquid-aurora-progress__loading-text {
color: white;
font-size: 18px;
font-weight: 600;
letter-spacing: 1px;
animation: darma-loader-uiverse-liquid-aurora-progress-textGlow 1s ease-in-out infinite;
}

.darma-loader-uiverse-liquid-aurora-progress__dot {
margin-left: 3px;
animation: darma-loader-uiverse-liquid-aurora-progress-blink 1.5s infinite;
}
.darma-loader-uiverse-liquid-aurora-progress__dot:nth-of-type(1) {
animation-delay: 0s;
}
.darma-loader-uiverse-liquid-aurora-progress__dot:nth-of-type(2) {
animation-delay: 0.3s;
}
.darma-loader-uiverse-liquid-aurora-progress__dot:nth-of-type(3) {
animation-delay: 0.6s;
}

@keyframes darma-loader-uiverse-liquid-aurora-progress-fillProgress {
0% {
width: 4px;
}
25% {
width: 25%;
}
50% {
width: 50%;
}
75% {
width: 75%;
}
100% {
width: calc(100% - 4px);
}
}

@keyframes darma-loader-uiverse-liquid-aurora-progress-colorShift {
0% {
filter: hue-rotate(0deg) brightness(1);
}
33% {
filter: hue-rotate(120deg) brightness(1.1);
}
66% {
filter: hue-rotate(240deg) brightness(0.9);
}
100% {
filter: hue-rotate(360deg) brightness(1);
}
}

@keyframes darma-loader-uiverse-liquid-aurora-progress-textGlow {
0%,
100% {
opacity: 0.7;
text-shadow: 0 0 8px rgba(139, 92, 246, 0.3);
}
50% {
opacity: 1;
text-shadow: 0 0 16px rgba(139, 92, 246, 0.6);
}
}

@keyframes darma-loader-uiverse-liquid-aurora-progress-blink {
0%,
50% {
opacity: 1;
}
51%,
100% {
opacity: 0;
}
}

